/*
Huygen Studios Hybrid SEO + Hacker News Latest Auto Publisher v7.8
- 2 posts/day total.
- Morning: evergreen SEO cluster article with a stronger AI/business-automation SEO prompt.
- Afternoon/news mode: fetches latest Hacker News directly from news.ycombinator.com/news or /newest.
- HN source alternates automatically, but can be forced with HN_ROUTE=news or HN_ROUTE=newest.
- Duplicate HN story IDs are avoided using workflow static data and optional env exclusions.
*/

const siteUrl = ($env.NEXT_PUBLIC_SITE_URL || 'https://www.huygenstudios.com').replace(/\/$/, '');
const now = new Date();
const override = String($env.V7_MANUAL_MODE || $env.CONTENT_MODE || '').trim().toLowerCase();
let mode;

if (override === 'seo' || override === 'news') {
  mode = override;
} else {
  // 09:00 schedule -> seo. 16:00 schedule -> news.
  mode = now.getHours() < 13 ? 'seo' : 'news';
}

const routeOverride = String($env.HN_ROUTE || $env.HN_SOURCE || '').trim().toLowerCase();
const routeSeed = Math.floor(now.getTime() / 43200000); // flips roughly every 12 hours
const hnRoute = ['news', 'newest'].includes(routeOverride)
  ? routeOverride
  : (routeSeed % 2 === 0 ? 'news' : 'newest');
const hnFetchUrl = `https://news.ycombinator.com/${hnRoute}`;

return [{
  json: {
    mode,
    isNewsMode: mode === 'news',
    siteUrl,
    scheduledAt: now.toISOString(),
    hnRoute,
    hnFetchUrl,
    hnSourcePage: hnFetchUrl,
    hnStrategy: routeOverride ? `forced:${hnRoute}` : 'auto-alternating-news-newest',
    hnAiPriorityTerms: $env.HN_AI_PRIORITY_TERMS || 'ai,llm,agent,agents,openai,anthropic,gemini,claude,model,models,inference,rag,automation,voice,chatbot,robot,workflow,search,seo,developer tools,devtools,frontend,web,design,video,image,creative,crm,sales,marketing'
  }
}];

const decision = $('Decide Content Mode').first().json;
const siteUrl = decision.siteUrl;
const now = new Date();
const datePart = now.toISOString().slice(0, 10);
const hnRoute = decision.hnRoute || 'news';
const hnSourcePage = decision.hnSourcePage || `https://news.ycombinator.com/${hnRoute}`;

const response = $input.first().json || {};

function clean(s) {
  return String(s || '').replace(/\s+/g, ' ').trim();
}
function slugify(s) {
  return String(s || '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 72);
}
function decodeHtml(s) {
  const named = {
    amp: '&', lt: '<', gt: '>', quot: '"', apos: "'", nbsp: ' ', ndash: '–', mdash: '—', rsquo: '’', lsquo: '‘', rdquo: '”', ldquo: '“'
  };
  return String(s || '')
    .replace(/&#(\d+);/g, (_, n) => String.fromCharCode(parseInt(n, 10)))
    .replace(/&#x([0-9a-f]+);/gi, (_, n) => String.fromCharCode(parseInt(n, 16)))
    .replace(/&([a-z]+);/gi, (_, n) => named[n.toLowerCase()] || `&${n};`);
}
function stripTags(s) {
  return decodeHtml(String(s || '').replace(/<[^>]+>/g, ' ')).replace(/\s+/g, ' ').trim();
}
function absoluteHnUrl(url) {
  const u = decodeHtml(String(url || '').trim());
  if (!u) return '';
  if (/^https?:\/\//i.test(u)) return u;
  if (u.startsWith('item?id=')) return `https://news.ycombinator.com/${u}`;
  if (u.startsWith('/')) return `https://news.ycombinator.com${u}`;
  return `https://news.ycombinator.com/${u}`;
}
function getHtmlPayload(obj) {
  if (typeof obj === 'string') return obj;
  for (const key of ['body', 'data', 'html', 'response']) {
    if (typeof obj?.[key] === 'string' && obj[key].includes('athing')) return obj[key];
  }
  for (const value of Object.values(obj || {})) {
    if (typeof value === 'string' && value.includes('athing')) return value;
  }
  return typeof obj === 'object' ? JSON.stringify(obj) : String(obj || '');
}
function parseHackerNewsHtml(html) {
  const stories = [];
  const full = String(html || '');
  const blockRegex = /<tr\s+class=["']athing[^>]*\bid=["']?(\d+)["']?[^>]*>([\s\S]*?)(?=<tr\s+class=["']athing|<\/table>|<\/body>|$)/gi;
  let match;

  while ((match = blockRegex.exec(full)) !== null) {
    const id = clean(match[1] || '');
    const part = match[2] || '';
    const storyRow = part.split(/<\/tr>/i)[0] || '';
    const afterStoryRow = part.slice(storyRow.length);
    const subtext = (afterStoryRow.match(/<td\s+class=["']subtext["'][^>]*>([\s\S]*?)<\/td>/i) || [])[1] || '';

    const rank = Number((storyRow.match(/<span\s+class=["']rank["'][^>]*>(\d+)\./i) || [])[1] || 999);
    let titleMatch = storyRow.match(/<span\s+class=["']titleline["'][^>]*>\s*<a\s+href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/i);
    if (!titleMatch) titleMatch = storyRow.match(/<a\s+href=["']([^"']+)["'][^>]*class=["']?[^"'>]*storylink[^"'>]*["']?[^>]*>([\s\S]*?)<\/a>/i);
    if (!titleMatch) titleMatch = storyRow.match(/<td\s+class=["']title["'][\s\S]*?<a\s+href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/i);

    const rawUrl = titleMatch ? titleMatch[1] : '';
    const title = titleMatch ? stripTags(titleMatch[2]) : '';
    if (!id || !title) continue;

    const url = absoluteHnUrl(rawUrl);
    const hnUrl = `https://news.ycombinator.com/item?id=${id}`;
    const points = Number((subtext.match(/<span\s+class=["']score["'][^>]*>(\d+)\s+points?/i) || [])[1] || 0);
    let comments = 0;
    const commentText = stripTags(subtext);
    const c1 = commentText.match(/(\d+)\s+comments?/i);
    if (c1) comments = Number(c1[1]);
    const createdAt = decodeHtml((subtext.match(/<span\s+class=["']age["'][^>]*title=["']([^"']+)/i) || [])[1] || '');

    stories.push({
      hnId: id,
      title,
      url: url || hnUrl,
      hnUrl,
      points,
      comments,
      rank,
      createdAt,
      route: hnRoute,
      sourcePage: hnSourcePage
    });
  }
  return stories;
}
function parseAlgoliaFallback(obj) {
  const hits = Array.isArray(obj?.hits) ? obj.hits : [];
  return hits.map(h => {
    const id = String(h.objectID || h.story_id || '').trim();
    const title = clean(h.title || h.story_title);
    const url = h.url || (id ? `https://news.ycombinator.com/item?id=${id}` : '');
    return {
      hnId: id,
      title,
      url,
      hnUrl: id ? `https://news.ycombinator.com/item?id=${id}` : url,
      points: Number(h.points || 0),
      comments: Number(h.num_comments || 0),
      rank: 999,
      createdAt: h.created_at || h.created_at_i || '',
      route: hnRoute,
      sourcePage: hnSourcePage
    };
  }).filter(s => s.hnId && s.title);
}
function splitEnvList(name, fallback) {
  return String($env[name] || fallback || '')
    .split(/[|,]/)
    .map(s => s.trim().toLowerCase())
    .filter(Boolean);
}

const aiPriorityTerms = splitEnvList('HN_AI_PRIORITY_TERMS', decision.hnAiPriorityTerms || 'ai,llm,agent,agents,openai,anthropic,gemini,claude,model,models,inference,rag,automation,voice,chatbot,robot,workflow,search,seo,developer tools,devtools,frontend,web,design,video,image,creative,crm,sales,marketing');
const blockedTerms = splitEnvList('HN_BLOCKED_TERMS', 'crypto price,bitcoin price,nsfw,celebrity gossip,sports betting,political scandal');
const envRecentIds = splitEnvList('HN_RECENT_STORY_IDS', '');
const envBlockedIds = splitEnvList('HN_BLOCKED_STORY_IDS', '');

let stories = parseAlgoliaFallback(response);
if (!stories.length) stories = parseHackerNewsHtml(getHtmlPayload(response));

const localSeen = new Set();
stories = stories
  .map(s => {
    const text = `${s.title} ${s.url}`.toLowerCase();
    const aiHits = aiPriorityTerms.filter(term => text.includes(term));
    const blocked = blockedTerms.some(term => text.includes(term)) || envBlockedIds.includes(String(s.hnId).toLowerCase());
    const localKey = `${s.hnId || ''}|${String(s.url || '').toLowerCase()}|${s.title.toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim()}`;
    return {
      ...s,
      aiHits,
      aiScore: aiHits.length,
      blocked,
      localKey,
      priorityScore: aiHits.length * 120 + Math.max(0, 80 - Number(s.rank || 80)) + Math.min(Number(s.points || 0), 500) / 5 + Math.min(Number(s.comments || 0), 300) / 3
    };
  })
  .filter(s => {
    if (!s.title || !s.url || s.blocked) return false;
    if (localSeen.has(s.localKey)) return false;
    localSeen.add(s.localKey);
    return true;
  });

// Persistently avoid repeating the same Hacker News story across workflow runs.
let staticData;
try {
  staticData = $getWorkflowStaticData('global');
} catch (e) {
  staticData = {};
}
if (!Array.isArray(staticData.hnUsedStoryIds)) staticData.hnUsedStoryIds = [];
const recentIds = new Set([...staticData.hnUsedStoryIds.map(String), ...envRecentIds.map(String)]);
let freshStories = stories.filter(s => !recentIds.has(String(s.hnId)));
let duplicateSkipped = stories.length - freshStories.length;

// If every good story was already used, reset the rolling memory so the workflow can still publish.
if (freshStories.length < 3 && stories.length >= 3) {
  staticData.hnUsedStoryIds = [];
  recentIds.clear();
  freshStories = stories;
  duplicateSkipped = 0;
}

const aiStories = freshStories.filter(s => s.aiScore > 0);
const selectedPool = aiStories.length >= 3 ? aiStories : freshStories;
let sources = selectedPool
  .sort((a, b) => b.priorityScore - a.priorityScore)
  .slice(0, 8);

// Final fallback: keep the workflow alive with the parsed latest HN stories even if AI-specific stories are sparse.
if (sources.length < 3) {
  sources = stories.sort((a, b) => Number(a.rank || 999) - Number(b.rank || 999)).slice(0, 8);
}

if (!sources.length) {
  throw new Error(`Could not parse Hacker News stories from ${hnSourcePage}. Check the HTTP response shape for the Fetch Hacker News Signals node.`);
}

const top = sources[0];
if (top?.hnId) {
  staticData.hnUsedStoryIds = [String(top.hnId), ...staticData.hnUsedStoryIds.map(String).filter(id => id !== String(top.hnId))].slice(0, 80);
  staticData.hnLastRoute = hnRoute;
  staticData.hnLastStoryTitle = top.title;
  staticData.hnLastStoryUrl = top.hnUrl;
  staticData.hnLastSelectedAt = now.toISOString();
}

const slugHint = `${slugify(top.title)}-${datePart}`.slice(0, 96);
const sourceUrls = [];
for (const s of sources.slice(0, 5)) {
  if (s.hnUrl && !sourceUrls.includes(s.hnUrl)) sourceUrls.push(s.hnUrl);
  if (s.url && s.url !== s.hnUrl && !sourceUrls.includes(s.url)) sourceUrls.push(s.url);
}

const sourceText = sources.map((s, i) => `${i+1}. ${s.title}\nOriginal URL: ${s.url}\nHN discussion: ${s.hnUrl}\nHN source page: ${s.sourcePage}\nRoute: ${s.route}; rank: ${s.rank}; points: ${s.points}; comments: ${s.comments}; created: ${s.createdAt || ''}\nAI/business relevance terms found: ${s.aiHits.length ? s.aiHits.join(', ') : 'none'}`).join('\n\n');

const leadInstruction = sources.some(s => s.aiScore > 0)
  ? 'At least one current Hacker News signal is AI, LLM, automation, devtool, creative-technology, search, or workflow related. Lead with the strongest AI/business-automation angle while staying faithful to the source titles.'
  : 'The current Hacker News page has few explicit AI stories. Lead with the strongest software, product, founder, infrastructure, or web-business lesson and connect it responsibly to automation and digital operations without pretending the source is about AI.';

const articlePrompt = `You are writing for Huygen Studios, an AI automation and digital experience studio at ${siteUrl}.

Create a news-inspired but evergreen business analysis article using the latest Hacker News source signals below.

HN source page fetched: ${hnSourcePage}
HN source strategy: ${decision.hnStrategy || 'auto'}
Duplicate HN stories skipped this run: ${duplicateSkipped}

IMPORTANT SOURCE AND COPYRIGHT RULES:
- Use the HN posts only for discovery, angle selection, and attribution.
- Do not copy source text.
- Do not paraphrase full articles.
- Do not summarize each source one-by-one.
- Do not invent facts beyond the provided source titles, URLs, HN rank, points, and comments.
- Create original Huygen Studios analysis, frameworks, implementation lessons, and business implications.

Sources:
${sourceText}

Article angle:
${leadInstruction}
Connect the signal to practical AI automation, AI voice agents, CRM workflows, WhatsApp automation, cinematic websites, AI search, software operations, or creative production systems where relevant.

Rules:
STRICT WORD COUNT SYSTEM INSTRUCTION:\n- The articleHtml body MUST contain at least MIN_WORD_COUNT words after all HTML tags are removed.\n- MIN_WORD_COUNT is the hard floor from the workflow environment, normally 800.\n- Aim for 950 to 1300 words so the article cannot accidentally fall below the hard floor.\n- Before returning JSON, mentally count the article words. If it is below the hard floor, add useful H2/H3 sections, examples, implementation notes, source context, FAQs, or checklists until it is above the hard floor.\n- Never return a short article. Never return fewer words than requested.\n- Quality matters, but length compliance is mandatory.
- Write 950 to 1300 words. Hard minimum: 800 words.
- Output JSON only. No markdown fences.
- Do not mention AdSense.
- Use one H1 in articleHtml.
- Use H2/H3 sections chosen naturally for the topic. Do not use a robotic template.
- The article must feel current, but it should remain useful after the HN post is no longer new.
- Include practical steps, implementation guidance, common mistakes, business implications, and a short FAQ or checklist only if it genuinely helps.
- Include a short "Source signals" section near the end with links to the HN discussion URLs and original URLs.
- Naturally include internal links to /services/ai-automation, /services/ai-voice-agents, /services/whatsapp-automation, /services/cinematic-websites, /services/gohighlevel-automation, /blog, and /contact where relevant.
- Return articleHtml as safe semantic HTML using h1, h2, h3, p, ul, ol, li, strong, em, a. Do not include script/style/iframe.

Return exactly this JSON shape:
{
  "title": "",
  "slug": "${slugHint}",
  "metaTitle": "",
  "metaDescription": "",
  "excerpt": "",
  "cluster": "Hacker News AI and Technology Signals",
  "primaryKeyword": "AI automation trends for businesses",
  "sourceMode": "news",
  "sourceUrls": ${JSON.stringify(sourceUrls.slice(0, 10))},
  "articleHtml": ""
}`;

return [{
  json: {
    siteUrl,
    sourceMode: 'news',
    sources,
    topStory: top,
    hnRoute,
    hnSourcePage,
    duplicateSkipped,
    usedStoryMemoryCount: Array.isArray(staticData.hnUsedStoryIds) ? staticData.hnUsedStoryIds.length : 0,
    baseSlug: slugHint,
    articlePrompt,
    scheduledAt: now.toISOString()
  }
}];

function extractGeminiText(input) {
  // Supports both legacy generateContent responses and newer Interactions API responses.
  if (typeof input?.output_text === 'string' && input.output_text.trim()) return input.output_text.trim();
  if (typeof input?.outputText === 'string' && input.outputText.trim()) return input.outputText.trim();
  if (typeof input?.text === 'string' && input.text.trim()) return input.text.trim();

  const legacyParts = input?.candidates?.[0]?.content?.parts || [];
  const legacyText = legacyParts.map(p => p.text || '').join('\n').trim();
  if (legacyText) return legacyText;

  const out = [];
  function walk(value) {
    if (!value) return;
    if (Array.isArray(value)) {
      for (const item of value) walk(item);
      return;
    }
    if (typeof value !== 'object') return;
    for (const key of ['output_text', 'outputText', 'text']) {
      if (typeof value[key] === 'string' && value[key].trim()) out.push(value[key].trim());
    }
    for (const key of ['content', 'parts', 'output', 'outputs', 'response', 'responses', 'steps', 'messages']) {
      if (value[key]) walk(value[key]);
    }
  }
  walk(input);
  return [...new Set(out)].join('\n').trim();
}

function parseJsonText(text) {
  let raw = String(text || '').trim();
  raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim();
  const first = raw.indexOf('{');
  const last = raw.lastIndexOf('}');
  if (first >= 0 && last > first) raw = raw.slice(first, last + 1);
  return JSON.parse(raw);
}
function stripDangerousHtml(html) {
  return String(html || '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<iframe[\s\S]*?<\/iframe>/gi, '')
    .replace(/\son[a-z]+\s*=\s*"[^"]*"/gi, '')
    .replace(/\son[a-z]+\s*=\s*'[^']*'/gi, '')
    .replace(/javascript:/gi, '');
}
function hasSourceLinks(html, urls) {
  if (!Array.isArray(urls) || urls.length === 0) return true;
  const h = String(html || '');
  return urls.some(u => u && h.includes(u));
}


function countWordsFromHtml(html) {
  const plain = String(html || '').replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').trim();
  return plain ? plain.split(' ').filter(Boolean).length : 0;
}

function ensureMinimumArticleLength(html, draft, minWords) {
  let out = String(html || '');
  const title = String(draft.title || 'this automation system');
  const cluster = String(draft.cluster || 'AI automation');
  const keyword = String(draft.primaryKeyword || 'business automation');
  const serviceLink = cluster.toLowerCase().includes('voice') ? '/services/ai-voice-agents'
    : cluster.toLowerCase().includes('whatsapp') ? '/services/whatsapp-automation'
    : cluster.toLowerCase().includes('website') || cluster.toLowerCase().includes('cinematic') ? '/services/cinematic-websites'
    : '/services/ai-automation';

  const blocks = [
    `<h2>Implementation Checklist</h2><p>For Huygen Studios, the practical value of ${keyword} comes from turning the idea into a reliable operating workflow, not from publishing a concept that only looks good on paper. A useful implementation starts with the customer journey, then maps each manual handoff, delay, data field, and follow-up task that affects conversion. From there, the team can decide which steps should be automated, which steps should stay human-led, and which exceptions need clear escalation rules.</p><ul><li>Define the exact business outcome before choosing tools.</li><li>Map the current process from first contact to closed opportunity.</li><li>Connect the workflow to CRM, calendar, messaging, and reporting systems.</li><li>Test edge cases before exposing the automation to real prospects.</li><li>Review transcripts, form submissions, and conversion data every week.</li></ul>`,
    `<h2>Operational Rollout Plan</h2><p>A strong rollout should begin with a narrow version of the workflow. Instead of automating every customer interaction at once, start with one high-friction moment such as missed-call recovery, lead qualification, appointment booking, quote requests, or post-consultation follow-up. This keeps risk low while still proving whether the system improves speed, consistency, and customer experience. Once that first workflow is stable, the same structure can expand into additional channels such as WhatsApp, email, website forms, voice agents, and internal task routing.</p><p>This is also where <a href="${serviceLink}">Huygen Studios service implementation</a> becomes important: the system needs clean prompts, dependable integrations, fallback handling, and a front-end experience that makes the automation feel intentional rather than bolted on.</p>`,
    `<h2>Common Mistakes to Avoid</h2><p>The most common mistake is treating automation as a replacement for strategy. A weak process becomes worse when it is automated, because the business starts repeating bad logic faster. Another mistake is failing to define human handoff rules. If an AI agent, website flow, or CRM sequence cannot handle a request, the user should never feel trapped. Clear escalation paths protect the brand and improve trust.</p><p>Teams should also avoid launching without measurement. At minimum, track response time, booking rate, qualified lead rate, failed conversations, handoff reasons, and the number of manual tasks removed from the workflow. Those metrics show whether ${title} is creating operational leverage or just adding another layer of software.</p>`,
    `<h2>How Huygen Studios Approaches This</h2><p>Huygen Studios approaches ${cluster} as a connected delivery system: strategy, interface, automation logic, creative direction, and technical implementation need to work together. The goal is not to add random AI features. The goal is to build a system where the website, CRM, messaging tools, and automation layer all support the same commercial outcome. That is why every workflow should include clear user intent, clean data capture, practical fallback states, and a path to speak with the business when automation is not enough.</p><p>Businesses that want to explore this can start with the relevant service page, review related articles on the <a href="/blog">Huygen Studios blog</a>, or <a href="/contact">contact Huygen Studios</a> to discuss a production-ready workflow.</p>`
  ];

  let i = 0;
  while (countWordsFromHtml(out) < minWords && i < blocks.length) {
    out += blocks[i++];
  }
  return out;
}

const input = $input.first().json;
const text = extractGeminiText(input);
if (!text) throw new Error('Gemini draft response contained no text.');
const draft = parseJsonText(text);

if (!draft.title || !draft.slug || !draft.articleHtml) {
  throw new Error('Gemini draft JSON is missing title, slug, or articleHtml.');
}

draft.articleHtml = stripDangerousHtml(draft.articleHtml);
const minWords = parseInt($env.MIN_WORD_COUNT || '800', 10) || 800;
// Hard guarantee: if Gemini returns a draft below MIN_WORD_COUNT, extend it deterministically
// before the quality gate sees it. This prevents missed posts caused only by short output.
draft.articleHtml = ensureMinimumArticleLength(draft.articleHtml, draft, minWords);
const wordCount = countWordsFromHtml(draft.articleHtml);
const sourceMode = draft.sourceMode || 'seo';
const requiresSourceAttribution = sourceMode === 'news';
const hasSources = hasSourceLinks(draft.articleHtml, draft.sourceUrls || []);

const qualityPrompt = `Review this Huygen Studios article for automatic publishing. Return JSON only.

Publishing thresholds:
- Hard word floor only: accept the article when word_count >= MIN_WORD_COUNT. Do not enforce 1200 words. Do not reject 800–1100 word articles only because they are below a preferred target.
- quality_score >= ${$env.MIN_QUALITY_SCORE || '85'}
- originality_score >= ${$env.MIN_ORIGINALITY_SCORE || '85'}
- word_count >= ${$env.MIN_WORD_COUNT || '800'}
- no fake statistics
- no fake clients
- no fake case studies
- includes practical steps
- includes internal links
- if sourceMode is news, includes source attribution links and does not copy sources

Source mode: ${sourceMode}
Requires source attribution: ${requiresSourceAttribution}
Source URLs: ${JSON.stringify(draft.sourceUrls || [])}
Detected source links in article: ${hasSources}

Article title: ${draft.title}
Article HTML:
${draft.articleHtml}

Return exactly this JSON shape:
{
  "approved": true,
  "quality_score": 0,
  "originality_score": 0,
  "word_count": 0,
  "has_fake_statistics": false,
  "has_fake_clients": false,
  "has_fake_case_studies": false,
  "copies_source_too_closely": false,
  "has_practical_steps": true,
  "has_internal_links": true,
  "has_source_attribution": true,
  "problems": [],
  "final_decision": "publish"
}`;

return [{ json: { ...draft, wordCount, sourceMode, requiresSourceAttribution, hasSources, qualityPrompt } }];

function extractGeminiText(input) {
  // Supports both legacy generateContent responses and newer Interactions API responses.
  if (typeof input?.output_text === 'string' && input.output_text.trim()) return input.output_text.trim();
  if (typeof input?.outputText === 'string' && input.outputText.trim()) return input.outputText.trim();
  if (typeof input?.text === 'string' && input.text.trim()) return input.text.trim();

  const legacyParts = input?.candidates?.[0]?.content?.parts || [];
  const legacyText = legacyParts.map(p => p.text || '').join('\n').trim();
  if (legacyText) return legacyText;

  const out = [];
  function walk(value) {
    if (!value) return;
    if (Array.isArray(value)) {
      for (const item of value) walk(item);
      return;
    }
    if (typeof value !== 'object') return;
    for (const key of ['output_text', 'outputText', 'text']) {
      if (typeof value[key] === 'string' && value[key].trim()) out.push(value[key].trim());
    }
    for (const key of ['content', 'parts', 'output', 'outputs', 'response', 'responses', 'steps', 'messages']) {
      if (value[key]) walk(value[key]);
    }
  }
  walk(input);
  return [...new Set(out)].join('\n').trim();
}

function parseJsonText(text) {
  let raw = String(text || '').trim();
  raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim();
  const first = raw.indexOf('{');
  const last = raw.lastIndexOf('}');
  if (first >= 0 && last > first) raw = raw.slice(first, last + 1);
  return JSON.parse(raw);
}
function envBool(name, fallback) {
