  quality.has_practical_steps === true &&
  quality.has_internal_links === true &&
  sourceAttributionOk &&
  blockingProblems.length === 0
);
const approved = objectivePass;

const categoryId = ($env.MARBLE_CATEGORY_ID || 'cmrds2w4y000009j7e37o136k').trim();
const authorId = ($env.MARBLE_AUTHOR_ID || '').trim();
const tagIds = ($env.MARBLE_TAG_IDS || '').split(',').map(s => s.trim()).filter(Boolean);

const siteUrl = String($env.NEXT_PUBLIC_SITE_URL || 'https://www.huygenstudios.com').replace(/\/$/, '');
let slug = slugify(draft.slug || draft.title);
if (!slug) slug = `post-${new Date().toISOString().replace(/[^0-9]/g, '').slice(0, 14)}`;
if (draft.sourceMode === 'news' && !/\d{4}-\d{2}-\d{2}$/.test(slug)) {
  slug = `${slug}-${new Date().toISOString().slice(0,10)}`.slice(0, 96);
}

const description = String(draft.metaDescription || draft.excerpt || '').trim()
  || stripHtmlText(draft.articleHtml).slice(0, 220)
  || String(draft.title || 'Huygen Studios article');
const { coverImage, coverImageSource } = resolveCoverImage(draft, slug, siteUrl);

const marbleBody = {
  title: String(draft.title || '').trim(),
  content: String(draft.articleHtml || '').trim(),
  description,
  slug,
  categoryId,
  status: 'published',
  featured: false,
  publishedAt: new Date().toISOString()
};
// Never send coverImage:null. Marble accepts a URL or null, but omitting the field is
// safer for frontends and lets the page-level fallback handle posts with no asset.
if (coverImage) marbleBody.coverImage = coverImage;
if (authorId) marbleBody.authors = [authorId];
if (tagIds.length) marbleBody.tags = tagIds;

let status = approved ? (autoPublish ? 'ready_to_publish' : 'dry_run_passed') : 'quality_gate_failed';
let shouldPublish = approved && autoPublish;
let blockingReason = '';

// Marble write operations require a private API key that starts with msk_.
// Public mpk_ keys are read-only and cause Marble HTTP 403. Guard here so the
// workflow returns a clear result instead of failing at the HTTP Request node.
if (autoPublish && approved && (marbleKeyMissing || marbleKeyLooksPublic || !marbleKeyLooksPrivate)) {
  shouldPublish = false;
  status = 'marble_private_key_required';
  blockingReason = marbleKeyMissing
    ? 'MARBLE_API_KEY is missing.'
    : marbleKeyLooksPublic
      ? 'MARBLE_API_KEY starts with mpk_, which Marble treats as a public/read-only key. Use a private write key that starts with msk_.'
      : 'MARBLE_API_KEY does not look like a Marble private write key. Use a private write key that starts with msk_.';
}

return [{
  json: {
    ...draft,
    repairAttempt: true,
    slug,
    quality,
    qualityProblems,
    blockingProblems,
    objectivePass,
    approved,
    autoPublish,
    shouldPublish,
    status,
    blockingReason,
    marbleKeyPrefix: marbleApiKey ? marbleApiKey.slice(0, 4) : '',
    siteUrl,
    publicPostPath: `/blog/${slug}`,
    coverImage: coverImage || null,
    coverImageSource,
    marbleBody
  }
}];

const prepared = $('Should Publish?').first().json;
const response = $input.first().json || {};
const statusCode = Number(response.statusCode || response.status || 0);
const body = response.body && typeof response.body === 'object' ? response.body : response;
const existingPost = body?.post && typeof body.post === 'object' ? body.post : null;
const slug = String(prepared.slug || '').trim();
if (!slug) throw new Error('Cannot publish: prepared slug is empty.');

let marbleWriteMethod;
let marbleWriteUrl;
let marbleUpsertMode;
if (statusCode === 200 && existingPost) {
  marbleWriteMethod = 'PATCH';
  marbleWriteUrl = `https://api.marblecms.com/v1/posts/${encodeURIComponent(existingPost.id || existingPost.slug || slug)}`;
  marbleUpsertMode = 'update-existing';
} else if (statusCode === 404) {
  marbleWriteMethod = 'POST';
  marbleWriteUrl = 'https://api.marblecms.com/v1/posts';
  marbleUpsertMode = 'create-new';
} else {
  throw new Error(`Marble slug preflight failed with HTTP ${statusCode || 'unknown'}: ${JSON.stringify(body).slice(0, 1000)}`);
}

return [{ json: {
  ...prepared,
  existingMarblePost: existingPost,
  marblePreflightStatusCode: statusCode,
  marbleWriteMethod,
  marbleWriteUrl,
  marbleUpsertMode,
  writeAttempt: 0,
  maxWriteAttempts: Math.max(1, parseInt($env.MARBLE_WRITE_MAX_ATTEMPTS || '4', 10) || 4)
} }];

const request = $('Prepare Marble Write Attempt').item.json;
const response = $input.first().json || {};
const statusCode = Number(response.statusCode || response.status || 0);
const body = response.body !== undefined ? response.body : response;
const attempt = Number(request.writeAttempt || 1);
const maxAttempts = Number(request.maxWriteAttempts || 4);
const method = String(request.marbleWriteMethod || 'POST').toUpperCase();
const slugUrl = `https://api.marblecms.com/v1/posts/${encodeURIComponent(request.slug)}`;

if (statusCode >= 200 && statusCode < 300) {
  return [{ json: {
    ...request,
    retryMarbleWrite: false,
    marbleWriteSucceeded: true,
    marbleWriteStatusCode: statusCode,
    marbleWriteResponse: body
  } }];
}

// A POST can race with another run or time out after Marble actually created the post.
// Convert a slug collision into a PATCH so the run becomes idempotent instead of failing.
if (statusCode === 409 && method === 'POST' && attempt < maxAttempts) {
  return [{ json: {
    ...request,
    marbleWriteMethod: 'PATCH',
    marbleWriteUrl: slugUrl,
    marbleUpsertMode: 'recover-409-with-update',
    retryMarbleWrite: true,
    marbleWriteSucceeded: false,
    marbleWriteStatusCode: statusCode,
    marbleWriteResponse: body
  } }];
}

// If the post vanished between preflight and PATCH, retry once as a create.
if (statusCode === 404 && method === 'PATCH' && attempt < maxAttempts) {
  return [{ json: {
    ...request,
    marbleWriteMethod: 'POST',
    marbleWriteUrl: 'https://api.marblecms.com/v1/posts',
    marbleUpsertMode: 'recover-404-with-create',
    retryMarbleWrite: true,
    marbleWriteSucceeded: false,
    marbleWriteStatusCode: statusCode,
    marbleWriteResponse: body
  } }];
}

const transient = [408, 425, 429].includes(statusCode) || statusCode >= 500 || statusCode === 0;
if (transient && attempt < maxAttempts) {
  return [{ json: {
    ...request,
    retryMarbleWrite: true,
    marbleWriteSucceeded: false,
    marbleWriteStatusCode: statusCode,
    marbleWriteResponse: body
  } }];
}

throw new Error(`Marble ${method} failed after ${attempt}/${maxAttempts} attempts with HTTP ${statusCode || 'unknown'}: ${JSON.stringify(body).slice(0, 1400)}`);

function addQueryParams(rawUrl, params) {
  const base = String(rawUrl || '').trim();
  if (!base) return '';
  let url;
  try { url = new URL(base); }
  catch (e) { throw new Error(`HUYGEN_REVALIDATE_URL is not a valid absolute URL: ${base}`); }
  for (const [key, value] of Object.entries(params)) {
    if (value !== undefined && value !== null && String(value) !== '') url.searchParams.set(key, String(value));
  }
  return url.toString();
}

const prepared = $('Prepare Marble Upsert').first().json;
const writeResult = $('Evaluate Marble Write').last().json;
const response = $input.first().json || {};
const statusCode = Number(response.statusCode || response.status || 0);
const body = response.body && typeof response.body === 'object' ? response.body : response;
const post = body?.post;
if (statusCode < 200 || statusCode >= 300 || !post) {
  throw new Error(`Marble read-after-write verification failed with HTTP ${statusCode || 'unknown'}: ${JSON.stringify(body).slice(0, 1200)}`);
}
if (String(post.status || '').toLowerCase() !== 'published') {
  throw new Error(`Marble returned post ${post.slug || prepared.slug}, but status is ${post.status || 'unknown'} instead of published.`);
}

const slug = String(post.slug || prepared.slug).trim();
const siteUrl = String(prepared.siteUrl || $env.NEXT_PUBLIC_SITE_URL || 'https://www.huygenstudios.com').replace(/\/$/, '');
const publicPath = `/blog/${slug}`;
const publicUrl = `${siteUrl}${publicPath}`;
const secret = String($env.HUYGEN_REVALIDATE_SECRET || $env.REVALIDATE_SECRET || '').trim();
const revalidateUrl = addQueryParams($env.HUYGEN_REVALIDATE_URL, {
  slug,
  path: publicPath,
  url: publicUrl,
  paths: JSON.stringify(['/blog', publicPath]),
  secret
});
const separator = publicUrl.includes('?') ? '&' : '?';
const publicVerificationUrl = `${publicUrl}${separator}__n8n_publish_check=${Date.now()}`;

return [{ json: {
  ...prepared,
  slug,
  publicPath,
  publicUrl,
  publicVerificationUrl,
  hasRevalidateUrl: Boolean(revalidateUrl),
  revalidateUrl,
  marbleWriteMethod: writeResult.marbleWriteMethod,
  marbleWriteStatusCode: writeResult.marbleWriteStatusCode,
  marbleWriteResponse: writeResult.marbleWriteResponse,
  marblePost: post,
  marbleVerificationStatusCode: statusCode
} }];

const prepared = $('Prepare Post-Publish Verification').first().json;
let revalidationAttempted = prepared.hasRevalidateUrl === true;
let revalidationStatusCode = null;
if (revalidationAttempted) {
  try {
    const r = $('Revalidate Website').first().json || {};
    revalidationStatusCode = Number(r.statusCode || r.status || 0) || null;
  } catch (e) {}
}

const response = $input.first().json || {};
const statusCode = Number(response.statusCode || response.status || 0);
const body = typeof response.body === 'string'
  ? response.body
  : (typeof response.data === 'string' ? response.data : JSON.stringify(response.body || response.data || response));
const lower = String(body || '').toLowerCase();
const knownErrorPage = [
  'this page couldn’t load',
  "this page couldn't load",
  'a server error occurred',
  'next-error-h1',
  '>404</h1>',
  'page not found</title>'
].some(marker => lower.includes(marker));

if (statusCode < 200 || statusCode >= 400) {
  throw new Error(`Public blog verification returned HTTP ${statusCode || 'unknown'} for ${prepared.publicUrl}.`);
}
if (!body || body.length < 200) {
  throw new Error(`Public blog verification returned an unexpectedly small response for ${prepared.publicUrl}.`);
}
if (knownErrorPage) {
  throw new Error(`Public blog verification detected a rendered error page at ${prepared.publicUrl}.`);
}

return [{ json: {
  ...prepared,
  publicStatusCode: statusCode,
  revalidationAttempted,
  revalidationStatusCode,
  publicPageVerified: true,
  checkedAt: new Date().toISOString()
} }];
